const { encode, decode } = require('./spec/hyperschema')

async function encrypt(data, cb) {
  const result = await cb(data)

  return encode('@encryption/encrypted-data', result)
}

async function decrypt(data, cb) {
  const decoded = decode('@encryption/encrypted-data', data)
  const decrypted = await cb(decoded)

  return decrypted
}

module.exports = { encrypt, decrypt }
